// // This module implements a 3-bit down-counter with asynchronous reset and enable
module up_counter_with_enable(
    input clk,
    input reset,
    input enable,
    output reg [2:0] count
    );

    always @(posedge clk) begin
        if (reset) begin
            count <= 3'b000;
        end else if (enable) begin
            count <= count + 1;
        end
    end
endmodule
